package main

import (
    "fmt"
    "strings"
)

func main() {
    s := "Hello, Go World!"
    fmt.Println("Length:", len(s))
    fmt.Println("Uppercase:", strings.ToUpper(s))
    fmt.Println("Contains Go:", strings.Contains(s, "Go"))
    fmt.Println(strings.ReplaceAll(s, "o", "0"))
}
